_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_main, vUv ).xyz;

    // feather pen
    ret += max(
      texture( sampler_main, (vUv-0.5)*(1-3*length(uTexSize.zw))*0.5+0.5 ).xyz,
      texture( sampler_main, (vUv-0.5)*(1+3*length(uTexSize.zw))*0.5+0.5 ).xyz
    )*0.3;

    // darken over uTime
    ret -= 0.35 / (audioLowSmooth*2.5); //Just a tweak with audioLow-controlled gamma.

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv1 = (vUv-0.5)*uAspect.xy;

//float ang1 = atan(uv1.y, uv1.x);
//float rad1 = log(length(uv1)-0.1);

float rad2 = length(uv1) + .1;
float ang2 = atan(uv1.y, uv1.x) * 1.5;

ang2 += uTime*0.05 - sin(uTime*0.1)*0.04;

vec2 uv2 = vec2(ang2, rad2);
uv2.y *= 0.85;
//uv2.x += uTime*0.05;
//uv2.y += sin(uTime*0.1)*0.05;

vec2 uv3 = uv2;
//uv3.x -= 0.05;
//uv3.y -= 0.05;

float ang3 = atan(uv3.y, uv3.x);
float rad3 = length(uv3);
vec2 uv4 = vec2 (ang3/rad3, rad3);

//uv4.x += uTime*0.05;
uv4.y *= 0.8;

float ang4 = atan(uv4.y, uv4.x);
float c = cos(ang4*24);
float s = sin(ang4*24);
float x = uv4.x*c - uv4.y*s;
float y = uv4.x*s + uv4.y*c;
uv4 = vec2(x,y)*0.8 + 0.5;

ret = texture(sampler_main, uv4).xyz;
//ret = mix(ret, 1, rad3*0.8);

  fragColor = ret;
}
